sections.code_example:
try:
    number = int("42")
except ValueError:
    print("That was not a number")
else:
    print("Conversion succeeded! Value:", number)

print("Done")

try:
    result = 10 / 2
except ZeroDivisionError:
    print("Division error!")
else:
    print("Result:", result)
finally:
    print("This always runs, no matter what.")

print("---")

try:
    result = 10 / 0
except ZeroDivisionError:
    print("Division error!")
finally:
    print("Cleanup complete.")

